import { useParams } from "react-router-dom";
import "./SalaryHistory.css";

function SalaryHistory() {
  const { id } = useParams();

  // Temporary static data (can be dynamic later)
  const salaryData = [
    {
      empId: "yousaf222",
      salary: 1000,
      allowance: 50,
      deduction: 40,
      total: 1010,
      payDate: "09/11/2024",
    },
  ];

  return (
    <div className="salary-page">
      <h2>Salary History</h2>

      <input
        type="text"
        placeholder="Search By Emp ID"
        className="search-box"
      />

      <table className="salary-table">
        <thead>
          <tr>
            <th>SNO</th>
            <th>EMP ID</th>
            <th>SALARY</th>
            <th>ALLOWANCE</th>
            <th>DEDUCTION</th>
            <th>TOTAL</th>
            <th>PAY DATE</th>
          </tr>
        </thead>

        <tbody>
          {salaryData.map((row, index) => (
            <tr key={index}>
              <td>{index + 1}</td>
              <td>{row.empId}</td>
              <td>{row.salary}</td>
              <td>{row.allowance}</td>
              <td>{row.deduction}</td>
              <td>{row.total}</td>
              <td>{row.payDate}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default SalaryHistory;
